import java.util.*;
import java.util.stream.*;

public class Main {
    static final class Stack {
        private final ArrayDeque<Integer> values = new ArrayDeque<>();
        void push(int value) { values.push(value); }
        boolean isEmpty() { return values.isEmpty(); }
        int pop() { return values.pop(); }
    }

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        Stack stack = new Stack();
        while (input.hasNextInt()) stack.push(input.nextInt());
        boolean first = true;
        while (!stack.isEmpty()) { if (!first) System.out.print(" " ); System.out.print(stack.pop()); first = false; }
        System.out.println();
    }
}
